image1 = imread(fullpath(getIPCVpath() + "/images/opencv_left01.jpg"));
image1 = imresize(image1, [240 320]);
image2 = imread(fullpath(getIPCVpath() + "/images/opencv_left02.jpg"));
image2 = imresize(image2, [240 320]);
comparison = imshowpair(image1, image2, "falsecolor");
imshow(comparison);
